import { render, screen } from "@testing-library/react";
import { MemoryRouter } from "react-router-dom";
import App from "./App";

test("renders the admin dashboard at /admin", () => {
  render(
    <MemoryRouter initialEntries={["/admin"]}>
      <App />
    </MemoryRouter>
  );

  expect(screen.getByText("Good morning, Admin.")).not.toBeNull();
  expect(screen.getAllByText("Product Management").length).toBeGreaterThan(0);
  expect(screen.getByText("10-Minute Order Queue")).not.toBeNull();
});
